INSERT INTO BOARD ( BOARD_ID, TITLE, CONTENT, WRITER, CREATED_AT ) VALUES ( #{boardId}, /* 위에서 가로챈 번호를 여기서 사용합니다 */ #{title}, #{content}, #{writer}, SYSDATE )

